def match_parens(lst):
    def is_balanced(s):
        stack = []
        for c in s:
            if c == '(':
                stack.append(c)
            elif c == ')':
                if not stack:
                    return False
                stack.pop()
        return not stack

    return 'Yes' if is_balanced(lst[0]) and is_balanced(lst[1]) else 'No'

